bool _isChecked = false;
int? _selectedRadio = 0;
bool _isSwitched = false;

Column(
  children: [
    Checkbox(
      value: _isChecked,
      onChanged: (bool? value) {
        setState(() { _isChecked = value!; });
      },
    ),
    Row(
      children: [
        Radio<int>(
          value: 0,
          groupValue: _selectedRadio,
          onChanged: (int? value) {
            setState(() { _selectedRadio = value; });
          },
        ),
        Radio<int>(
          value: 1,
          groupValue: _selectedRadio,
          onChanged: (int? value) {
            setState(() { _selectedRadio = value; });
          },
        ),
      ],
    ),
    Switch(
      value: _isSwitched,
      onChanged: (bool value) {
        setState(() { _isSwitched = value; });
      },
    ),
  ],
);
